import math
class Solution:
    def internalAngles(self, sides):
        a, b, c = sides
        if a + b <= c or b + c <= a or a + c <= b:
            return []
        angs = []
        for x, y, z in [(a, b, c), (b, a, c), (c, a, b)]:
            cosv = (y * y + z * z - x * x) / (2.0 * y * z)
            cosv = max(-1.0, min(1.0, cosv))
            angs.append(math.degrees(math.acos(cosv)))
        angs.sort()
        return angs

